import { isString } from 'lodash-es';

import { colorPaletteOptions, ColorPalette } from '../types/color-palette.js';

/**
 * Returns true if colorPalette is a valid ColorPalette
 * @param colorPalette - color palette
 */
export const isValidColorPalette = (
  colorPalette: unknown,
): colorPalette is ColorPalette => {
  return (
    isString(colorPalette) &&
    (colorPaletteOptions as unknown as string[]).includes(colorPalette ?? '')
  );
};
